import React, { createContext, useEffect, useState } from "react";
import { io } from "socket.io-client";

const SocketContext = createContext(null);

export const SocketProvider = ({ children }) => {
  const [socket, setSocket] = useState(null);

  useEffect(() => {
    // Connect to backend Socket.IO server
    let s;
    const connectWithToken = (tokenValue) => {
      if (s) {
        try {
          s.disconnect();
        } catch (e) {}
      }
      s = io("http://localhost:3002", {
        transports: ["websocket", "polling"],
        auth: { token: tokenValue },
        autoConnect: true,
      });

      setSocket(s);

      s.on("connect", () => {
        console.log("Socket connected ->", s.id);
      });

      s.on("disconnect", () => {
        console.log("Socket disconnected");
      });
    };

    // initial connect
    connectWithToken(localStorage.getItem("token"));

    // When token changes in other tabs or after login, reconnect socket with new token
    const onStorage = (e) => {
      if (e.key === "token") {
        connectWithToken(e.newValue);
      }
    };

    window.addEventListener("storage", onStorage);

    return () => {
      window.removeEventListener("storage", onStorage);
      if (s) s.disconnect();
    };
  }, []);

  return <SocketContext.Provider value={socket}>{children}</SocketContext.Provider>;
};

export default SocketContext;
